@page "/privacy"
@attribute [RenderModeAttribute(0)]
@using Microsoft.AspNetCore.Http
@inject IHttpContextAccessor HttpContextAccessor

<PageTitle>Privacy Policy</PageTitle>

<h1>Privacy Policy</h1>

@if (HasConsented)
{
    <div class="alert alert-success">
        ✅ You have already accepted our cookie policy.
    </div>
}
else
{
    <div class="alert alert-warning">
        ⚠️ You have not yet accepted our cookie policy.
    </div>
}

<h2>How We Use Cookies</h2>
<p>
    This application uses cookies to improve your experience. By using our site,
    you acknowledge that you have read and understand our cookie policy.
</p>

<h2>Data Collection</h2>
<p>
    We collect only the minimum data necessary to provide our services.
    Your personal information is never sold to third parties.
</p>

@code {
    private bool HasConsented { get; set; }

    protected override void OnInitialized()
    {
        var httpContext = HttpContextAccessor.HttpContext;
        if (httpContext is not null)
        {
            HasConsented = httpContext.Request.Cookies.ContainsKey("consent");
        }
    }
}

using System;

namespace Microsoft.AspNetCore.Components;

/// <summary>
/// Marks a page to opt out of global interactive rendering.
/// Mode = 0 means static SSR only.
/// </summary>
[AttributeUsage(AttributeTargets.Class)]
public class RenderModeAttribute : Attribute
{
    public int Mode { get; }

    public RenderModeAttribute(int mode)
    {
        Mode = mode;
    }
}

