@code {
    [CascadingParameter]
    private HttpContext? HttpContext { get; set; }

    private IComponentRenderMode? PageRenderMode =>
        AssignedRenderMode is null ? null : InteractiveServer;

    private static readonly IComponentRenderMode InteractiveServer =
        RenderMode.InteractiveServer;

    // When the page declares no render mode (via the attribute), AssignedRenderMode
    // is null and we fall through to static SSR. Otherwise we use InteractiveServer.
    private IComponentRenderMode? AssignedRenderMode =>
        HttpContext?.GetEndpoint()?.Metadata
            .GetMetadata<RenderModeAttribute>() is { Mode: 0 }
            ? null
            : InteractiveServer;
}
"}

